#include<bits/stdc++.h>
using namespace std;
int fa[500010],cnt[500010],u[500010],v[500010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
vector<pair<int,int>> mp[500010];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    if(n<=3)
    {
        printf("-1");
        return 0;
    }
    for(int i=1;i<=m;i++)
    {
        fa[i]=i;
        scanf("%d%d",&u[i],&v[i]);
        cnt[u[i]]++;
        cnt[v[i]]++;
        mp[u[i]].push_back({v[i],i});
        mp[v[i]].push_back({u[i],i});
    }
    int f=0;
    for(int i=1;i<=m;i++)
    {
        if(cnt[u[i]]==1||cnt[v[i]]==1)
        {
            f=u[i];
            merge(u[i],v[i]);
        }
    }
    int flag=0;
    for(int i=1;i<=n;i++)
    {
        if(find(i)!=find(1))
        {
            flag=1;
            break;
        }
    }
    if(!flag)
    {
        printf("-1");
        return 0;
    }
    if(!f)
    {
        int min1=0,min2=0,id=0;
        for(int i=1;i<=n;i++)
        {
            if(min1==0||cnt[i]<cnt[min1])
            {
                min1=i;
            }
        }
        for(auto i:mp[min1])
        {
            if(min2==0||cnt[i.first]<cnt[min2])
            {
                min2=i.first;
                id=i.second;
            }
        }
        set<int> s;
        for(auto i:mp[min1])
        {
            s.insert(i.second);
        }
        for(auto i:mp[min2])
        {
            s.insert(i.second);
        }
        s.erase(id);
        printf("%d\n",(int)(s.size()));
        for(int i:s)
        {
            printf("%d %d\n",u[i],v[i]);
        }
        return 0;
    }
    set<int> s;
    for(int i=1;i<=n;i++)
    {
        if(find(i)==find(f))
        {
            for(auto j:mp[i])
            {
                if(find(j.first)==find(f))
                {
                    continue;
                }
                s.insert(j.second);
            }
        }
    }
    printf("%d\n",(int)(s.size()));
    for(int i:s)
    {
        printf("%d %d\n",u[i],v[i]);
    }
    return 0;
}
